<?php
namespace App\Modules\Hr\Training\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Training\Models\HrCertificate; use App\Modules\Hr\Training\Models\HrTrainingEnrollment; use Illuminate\Support\Facades\DB;
class RecordTrainingResultAction { public function __construct(private HrAuditService $audit){} public function execute(HrTrainingEnrollment $enrollment,int $progress,?float $score=null):HrTrainingEnrollment{abort_unless(auth()->user()?->hasHrPermission('hr.training.manage'),403);abort_unless($enrollment->legal_entity_id===app(TenantContext::class)->getId(),404);abort_if($progress<0||$progress>100||($score!==null&&($score<0||$score>100)),422);return DB::transaction(function()use($enrollment,$progress,$score){$row=HrTrainingEnrollment::withoutGlobalScope('tenant')->whereKey($enrollment->id)->lockForUpdate()->with('session.course')->firstOrFail();abort_if(in_array($row->status,['completed','failed','cancelled'],true),422,'Tamamlanmış eğitim sonucu değiştirilemez.');$course=$row->session->course;$passed=null;$status=$progress>0?'in_progress':'enrolled';if($progress===100){abort_if($course->passing_score!==null&&$score===null,422,'Sınav puanı zorunludur.');$passed=$course->passing_score===null||$score>=(float)$course->passing_score;$status=$passed?'completed':'failed';}$row->update(['progress_percent'=>$progress,'exam_score'=>$score,'passed'=>$passed,'status'=>$status,'completed_at'=>$progress===100?now():null]);if($passed){$issued=today();HrCertificate::firstOrCreate(['enrollment_id'=>$row->id],['legal_entity_id'=>$row->legal_entity_id,'employee_id'=>$row->employee_id,'course_id'=>$course->id,'certificate_number'=>sprintf('TRN-%d-%08d',$row->legal_entity_id,$row->id),'issued_on'=>$issued,'expires_on'=>$course->certificate_validity_months?$issued->copy()->addMonths($course->certificate_validity_months):null,'status'=>'valid']);}$this->audit->log('training_result_recorded',$row,null,['progress_percent'=>$progress,'exam_score'=>$score,'passed'=>$passed]);return $row->fresh(['certificate']);});} }
